What will be output of the following code snippet?
#include <stdio.h>
int main() {
  float x=5;
  if (x>10)
    printf("Greater");
  else if (x=10)
    printf("Equal");
  else
    printf("Smaller");
  return 0;
}

What will be output of the following code snippet?
#include <stdio.h>
int main() {
  int i;
  for (i=1;i<=5;i++) {
    if(i==i)
      continue;
    printf("%d", i);
  }
  return 0;
}

What will be the output of the following C code?
#include <stdio.h>
int main() {
  int a=10;
  int *p=&a;
  printf("%d\n",*p);
  return 0;
}

What will be the output of the following program?
char str1[20] = "Hello";
char str2[20] = "Hello";
strcpy(str2, str1);
if (strcmp(str1, str2) == 0)
  printf("Equal");
else
  printf("Not Equal");

What will be the output of the following C program?
#include <stdio.h>
int recur(int n) {
  if (n==0)
    return 0;
  else
    return n + recur(n-1);
}
int main() {
  int result = recur(4);
  printf("%d\n", result);
  return 0;
}

What will be the output of the following C code?
#include <stdio.h>
int main() {
  int x;
  x = 4<3 ? 100 : 3==3>2 ? 50 : 75;
  printf("%d", x);
  return 0;
}

Find the output from the following C++ code snippet:
class A {
public:
  void show() { cout<< "Class A\n"; }
};
class B public A {
public:
  void show() {
    A::show();
    cout<< "Class B";
  }
};
int main() {
  B obj;
  obj.show();
  return 0;
}

What will be the output of this program?
#include <iostream>
using namespace std;
class Test {
public:
  static int x;
  Test() { x++; }
  void display() { cout<< x << " "; }
};
int Test::x = 5;
int main() {
  Test t1;
  t1.display();
  Test t2;
  t2.display();
  return 0;
}

What is the output of the following C++ code?
#include <iostream>
using namespace std;
class Base {
public:
  virtual void show() { cout<< "Base"; }
};
class Derived : public public: Base {
public:
  void show() override { cout<< "Derived"; }
};
int main() {
  Base* ptr;
  Derived d;
  ptr = &d;
  ptr->show();
  return 0;
}
